//! Delegated Prover Server for zk-X509.
//!
//! Service operators deploy this server to generate ZK proofs on behalf of users.
//! The user sends pre-signed data (cert + signatures + consent); this server runs
//! the SP1 prover and returns the proof. The user's private key never reaches
//! this server — only signatures generated by the OS keychain are transmitted.
//!
//! Usage:
//!   RUST_LOG=info cargo run --release --bin prover-server
//!
//! Environment:
//!   PROVER_URL     - This server's public URL (for consent verification)
//!   PROVER_PORT    - Port to listen on (default: 9090)
//!   PROVER_LOG_DIR - Directory for compliance logs (default: ./logs)
//!
//! Endpoints:
//!   POST /api/prove      - Generate a ZK proof from pre-signed inputs
//!   GET  /api/pubkey     - ECIES public key for encrypting requests
//!   GET  /api/health     - Server status (SP1 version, prover URL)
//!   GET  /api/compliance - Query logged compliance records by wallet (KYC reconciliation)

use axum::{
    extract::{Json, Query, State},
    http::StatusCode,
    routing::{get, post},
    Router,
};
use alloy_sol_types::SolType;
use serde::{Deserialize, Serialize};
use sha2::{Digest, Sha256};
use zk_x509_lib::PublicValuesStruct;
use sp1_sdk::{
    blocking::{ProveRequest, Prover, ProverClient},
    include_elf, Elf, SP1ProofWithPublicValues,
};
use std::sync::Arc;
use std::time::{Instant, SystemTime, UNIX_EPOCH};
use tower_http::cors::{AllowOrigin, CorsLayer};

const ZK_X509_ELF: Elf = include_elf!("zk-x509-program");
const CONSENT_DOMAIN: &str = "zk-x509-delegated-proving-consent";

// ── Request / Response ──────────────────────────────────────────

#[derive(Deserialize)]
struct DelegatedProveRequest {
    // ── Encrypted mode: ECIES-encrypted sensitive payload ──
    #[serde(default)]
    encrypted_payload: Option<String>, // hex: ECIES ciphertext of SensitivePayload JSON

    // ── Plaintext mode (backward compatible): sensitive fields ──
    #[serde(default)]
    consent_signature: Option<String>,
    #[serde(default)]
    cert_der: Option<String>,           // base64
    #[serde(default)]
    cert_chain: Option<Vec<String>>,    // base64[]
    #[serde(default)]
    ownership_sig: Option<String>,      // hex
    #[serde(default)]
    nullifier_sig: Option<String>,      // hex

    // ── Always plaintext (non-sensitive metadata) ──
    registrant: String,          // 0x address
    wallet_index: u32,
    max_wallets: u32,
    disclosure_mask: u8,
    #[serde(default)]
    required_country: Option<String>,
    #[serde(default)]
    required_org: Option<String>,
    #[serde(default)]
    required_org_unit: Option<String>,
    #[serde(default)]
    required_common_name: Option<String>,
    chain_id: u64,
    registry_address: String,
    ca_merkle_root: String,
    ca_merkle_proof: Vec<String>,
    #[serde(default)]
    crl_data: Option<String>,
    #[serde(default)]
    _crl_merkle_root: Option<String>,
    timestamp: u64,
}

/// Sensitive data encrypted with ECIES.
#[derive(Deserialize)]
struct SensitivePayload {
    consent_signature: String,
    cert_der: String,
    cert_chain: Vec<String>,
    ownership_sig: String,
    nullifier_sig: String,
}

/// Parse an optional hex-encoded bytes32 string (0x-prefixed) into [u8; 32].
fn parse_optional_bytes32(val: &Option<String>) -> [u8; 32] {
    match val {
        Some(s) if !s.is_empty() => {
            let hex_str = s.strip_prefix("0x").unwrap_or(s);
            let bytes = hex::decode(hex_str).unwrap_or_default();
            let mut result = [0u8; 32];
            let len = bytes.len().min(32);
            result[..len].copy_from_slice(&bytes[..len]);
            result
        }
        _ => [0u8; 32],
    }
}

#[derive(Serialize)]
struct ProveResponse {
    proof: String,
    public_values: String,
    proving_time_ms: u64,
}

#[derive(Serialize)]
struct HealthResponse {
    status: String,
    sp1_version: String,
    prover_url: String,
}

#[derive(Serialize)]
struct ErrorResponse {
    error: String,
}

/// One compliance record — the single source of truth for both the
/// `compliance-{day}.jsonl` log line (written after a proof succeeds) and the
/// `GET /api/compliance` response. The admin KYC-reconciliation screen joins
/// `nullifier` against the on-chain IdentityRegistry registration and shows the
/// cert identity for review.
///
/// `#[serde(default)]` lets legacy log lines that predate the structured format
/// deserialize gracefully (unknown/missing fields fall back to defaults).
#[derive(Serialize, Deserialize, Default)]
#[serde(rename_all = "camelCase", default)]
struct ComplianceRecord {
    timestamp: u64,
    registrant: String,
    common_name: String,
    org: String,
    org_unit: String,
    country: String,
    serial: String,
    not_after: i64,
    nullifier: String,
    consent_verified: bool,
    consent_message: String,
    consent_signature: String,
}

#[derive(Serialize)]
struct ComplianceResponse {
    wallet: String,
    records: Vec<ComplianceRecord>,
}

/// Query params for `GET /api/compliance?wallet=0x..`.
#[derive(Deserialize)]
struct ComplianceQuery {
    wallet: String,
}

/// Server state: holds the ECIES private key for decrypting delegated requests.
#[derive(Clone)]
struct AppState {
    ecies_secret_key: [u8; 32],
    ecies_public_key: Vec<u8>, // 65 bytes uncompressed
}

impl AppState {
    fn new() -> Self {
        // Load from PROVER_ECIES_KEY env var, or load/generate from file
        let sk_bytes: [u8; 32] = if let Ok(hex_key) = std::env::var("PROVER_ECIES_KEY") {
            let bytes = hex::decode(hex_key.strip_prefix("0x").unwrap_or(&hex_key))
                .expect("PROVER_ECIES_KEY must be valid hex");
            bytes.try_into().expect("PROVER_ECIES_KEY must be exactly 32 bytes")
        } else {
            // Persist key to file so it survives restarts
            let key_path = std::path::PathBuf::from(
                std::env::var("PROVER_LOG_DIR").unwrap_or_else(|_| "./logs".to_string())
            ).join(".ecies_key");

            if key_path.exists() {
                let hex_key = std::fs::read_to_string(&key_path)
                    .expect("Failed to read ECIES key file");
                let bytes = hex::decode(hex_key.trim())
                    .expect("Invalid hex in ECIES key file");
                bytes.try_into().expect("ECIES key file must contain exactly 32 bytes")
            } else {
                // Generate random key
                let mut key = [0u8; 32];
                getrandom::getrandom(&mut key).expect("Failed to generate random key");
                std::fs::create_dir_all(key_path.parent().unwrap()).ok();
                std::fs::write(&key_path, hex::encode(key))
                    .expect("Failed to save ECIES key");
                // Restrict file permissions (owner read/write only)
                #[cfg(unix)]
                {
                    use std::os::unix::fs::PermissionsExt;
                    std::fs::set_permissions(&key_path, std::fs::Permissions::from_mode(0o600)).ok();
                }
                eprintln!("Generated new ECIES key: {}", key_path.display());
                key
            }
        };

        let sk = ecies::SecretKey::parse_slice(&sk_bytes)
            .expect("ECIES key is not a valid secp256k1 secret key");
        let pk = ecies::PublicKey::from_secret_key(&sk);
        let pk_bytes = pk.serialize().to_vec(); // 65 bytes uncompressed

        Self {
            ecies_secret_key: sk_bytes,
            ecies_public_key: pk_bytes,
        }
    }
}

#[derive(Serialize)]
struct PubkeyResponse {
    pubkey: String,
}

// ── Helpers ──────────────────────────────────────────────────────

fn decode_hex(s: &str) -> Result<Vec<u8>, String> {
    let s = s.strip_prefix("0x").unwrap_or(s);
    hex::decode(s).map_err(|e| format!("Invalid hex: {}", e))
}

fn decode_base64(s: &str) -> Result<Vec<u8>, String> {
    use base64::Engine;
    base64::engine::general_purpose::STANDARD
        .decode(s)
        .map_err(|e| format!("Invalid base64: {}", e))
}

fn decode_hash(s: &str) -> Result<[u8; 32], String> {
    let bytes = decode_hex(s)?;
    if bytes.len() != 32 {
        return Err(format!("Expected 32 bytes, got {}", bytes.len()));
    }
    let mut arr = [0u8; 32];
    arr.copy_from_slice(&bytes);
    Ok(arr)
}

fn decode_address(s: &str) -> Result<[u8; 20], String> {
    let bytes = decode_hex(s)?;
    if bytes.len() != 20 {
        return Err(format!("Expected 20 bytes, got {}", bytes.len()));
    }
    let mut arr = [0u8; 20];
    arr.copy_from_slice(&bytes);
    Ok(arr)
}

fn build_consent_message(
    prover_url: &str,
    registry_address: &str,
    chain_id: u64,
    registrant: &str,
    timestamp: u64,
) -> String {
    format!(
        "{}\nProver: {}\nRegistry: {}\nChain ID: {}\nWallet: {}\nTimestamp: {}",
        CONSENT_DOMAIN,
        prover_url,
        registry_address.to_lowercase(),
        chain_id,
        registrant.to_lowercase(),
        timestamp,
    )
}

/// Verify that the consent signature was produced by the certificate's private key.
fn verify_consent(
    cert_der: &[u8],
    consent_sig: &[u8],
    expected_message: &str,
) -> Result<(), String> {
    use x509_parser::prelude::FromDer;
    let (_, cert) = x509_parser::certificate::X509Certificate::from_der(cert_der)
        .map_err(|e| format!("Parse cert: {:?}", e))?;

    let prehash: [u8; 32] = Sha256::digest(expected_message.as_bytes()).into();
    let pub_key = cert.tbs_certificate.subject_pki.clone();
    let alg_oid = pub_key.algorithm.algorithm.to_id_string();

    if alg_oid == "1.2.840.113549.1.1.1" {
        // RSA
        use rsa::pkcs1v15::Pkcs1v15Sign;
        use rsa::pkcs8::DecodePublicKey;
        let rsa_pub = rsa::RsaPublicKey::from_public_key_der(pub_key.raw)
            .map_err(|e| format!("RSA parse: {}", e))?;
        rsa_pub.verify(Pkcs1v15Sign::new::<sha2::Sha256>(), &prehash, consent_sig)
            .map_err(|e| format!("RSA consent verify failed: {}", e))
    } else if alg_oid == "1.2.840.10045.2.1" {
        // ECDSA — detect curve from parameters
        let params = pub_key.algorithm.parameters.as_ref()
            .ok_or("Missing EC parameters")?;
        let curve_oid = params.as_oid()
            .map_err(|_| "Invalid EC curve OID".to_string())?
            .to_id_string();

        if curve_oid == "1.2.840.10045.3.1.7" {
            // P-256
            use p256::ecdsa::{VerifyingKey, Signature};
            use p256::ecdsa::signature::hazmat::PrehashVerifier;
            let vk = VerifyingKey::from_sec1_bytes(pub_key.subject_public_key.as_ref())
                .map_err(|e| format!("P-256 parse: {}", e))?;
            let sig = Signature::from_der(consent_sig)
                .map_err(|e| format!("P-256 sig parse: {}", e))?;
            vk.verify_prehash(&prehash, &sig)
                .map_err(|e| format!("P-256 consent verify failed: {}", e))
        } else if curve_oid == "1.3.132.0.34" {
            // P-384
            use p384::ecdsa::{VerifyingKey, Signature};
            use p384::ecdsa::signature::hazmat::PrehashVerifier;
            let vk = VerifyingKey::from_sec1_bytes(pub_key.subject_public_key.as_ref())
                .map_err(|e| format!("P-384 parse: {}", e))?;
            let sig = Signature::from_der(consent_sig)
                .map_err(|e| format!("P-384 sig parse: {}", e))?;
            vk.verify_prehash(&prehash, &sig)
                .map_err(|e| format!("P-384 consent verify failed: {}", e))
        } else {
            Err(format!("Unsupported EC curve: {}", curve_oid))
        }
    } else {
        Err(format!("Unsupported key algorithm: {}", alg_oid))
    }
}

/// Certificate identity fields extracted from the subject DN, for compliance
/// logging and the admin KYC reconciliation screen.
struct CertSubject {
    common_name: String,
    org: String,
    org_unit: String,
    country: String,
    serial: String, // 0x-prefixed hex
    not_after: i64, // unix seconds
}

/// Parse the certificate subject into individual RDN fields. A failed parse
/// yields empty fields so the compliance record always has a stable shape.
fn parse_cert_subject(cert_der: &[u8]) -> CertSubject {
    use x509_parser::prelude::FromDer;
    let first = |attr: Option<&x509_parser::x509::AttributeTypeAndValue>| {
        attr.and_then(|a| a.as_str().ok()).unwrap_or("").to_string()
    };
    match x509_parser::certificate::X509Certificate::from_der(cert_der) {
        Ok((_, c)) => CertSubject {
            common_name: first(c.subject().iter_common_name().next()),
            org: first(c.subject().iter_organization().next()),
            org_unit: first(c.subject().iter_organizational_unit().next()),
            country: first(c.subject().iter_country().next()),
            serial: format!("0x{}", hex::encode(c.raw_serial())),
            not_after: c.validity().not_after.timestamp(),
        },
        Err(_) => CertSubject {
            common_name: String::new(),
            org: String::new(),
            org_unit: String::new(),
            country: String::new(),
            serial: String::new(),
            not_after: 0,
        },
    }
}

/// Append a compliance record as one JSON line to `compliance-{day}.jsonl`.
/// Called only after the proof succeeds, so `record.nullifier` matches the
/// value registered on-chain — the key the admin KYC-reconciliation screen
/// joins on. The day partition is derived from `record.timestamp`.
///
/// NOTE: Service operators subject to KYC/AML regulations may extend the
/// `ComplianceRecord` to store additional data (e.g., full certificate DER,
/// disclosure fields) per their jurisdiction's data retention requirements;
/// the decrypted sensitive payload is available at the call site.
fn log_compliance(record: &ComplianceRecord) {
    let log_dir = std::env::var("PROVER_LOG_DIR").unwrap_or_else(|_| "./logs".to_string());
    let _ = std::fs::create_dir_all(&log_dir);
    let Ok(line) = serde_json::to_string(record) else {
        return;
    };
    let path = format!("{}/compliance-{}.jsonl", log_dir, record.timestamp / 86400);
    if let Ok(mut f) = std::fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(&path)
    {
        use std::io::Write;
        let _ = writeln!(f, "{}", line);
    }
}

// ── Handlers ────────────────────────────────────────────────────

async fn health_handler() -> Json<HealthResponse> {
    let prover_url = std::env::var("PROVER_URL")
        .unwrap_or_else(|_| "http://localhost:9090".to_string());
    Json(HealthResponse {
        status: "ok".to_string(),
        sp1_version: "v6.0.2".to_string(),
        prover_url,
    })
}

async fn pubkey_handler(State(state): State<Arc<AppState>>) -> Json<PubkeyResponse> {
    Json(PubkeyResponse {
        pubkey: format!("0x{}", hex::encode(&state.ecies_public_key)),
    })
}

/// GET /api/compliance?wallet=0x..
///
/// Returns every compliance record logged for the given wallet (registrant),
/// newest first, in the schema the admin KYC-reconciliation screen consumes.
/// Reads all `compliance-*.jsonl` files under `PROVER_LOG_DIR`; each line
/// deserializes into a `ComplianceRecord`, so legacy lines that predate a
/// field degrade gracefully to its default (via `#[serde(default)]`).
async fn compliance_handler(
    Query(q): Query<ComplianceQuery>,
) -> Result<Json<ComplianceResponse>, (StatusCode, Json<ErrorResponse>)> {
    let wallet = q.wallet.trim().to_lowercase();
    if decode_address(&wallet).is_err() {
        return Err((
            StatusCode::BAD_REQUEST,
            Json(ErrorResponse {
                error: "wallet must be a 0x-prefixed 20-byte address".to_string(),
            }),
        ));
    }

    let log_dir = std::env::var("PROVER_LOG_DIR").unwrap_or_else(|_| "./logs".to_string());
    let mut records: Vec<ComplianceRecord> = Vec::new();

    if let Ok(entries) = std::fs::read_dir(&log_dir) {
        for entry in entries.flatten() {
            let name = entry.file_name();
            let name = name.to_string_lossy();
            if !(name.starts_with("compliance-") && name.ends_with(".jsonl")) {
                continue;
            }
            let Ok(content) = std::fs::read_to_string(entry.path()) else {
                continue;
            };
            for line in content.lines() {
                let line = line.trim();
                if line.is_empty() {
                    continue;
                }
                let Ok(rec) = serde_json::from_str::<ComplianceRecord>(line) else {
                    continue;
                };
                if rec.registrant.eq_ignore_ascii_case(&wallet) {
                    records.push(rec);
                }
            }
        }
    }

    // Newest first.
    records.sort_by(|a, b| b.timestamp.cmp(&a.timestamp));

    Ok(Json(ComplianceResponse { wallet, records }))
}

async fn prove_handler(
    State(state): State<Arc<AppState>>,
    Json(req): Json<DelegatedProveRequest>,
) -> Result<Json<ProveResponse>, (StatusCode, Json<ErrorResponse>)> {
    let err = |msg: String| -> (StatusCode, Json<ErrorResponse>) {
        (StatusCode::BAD_REQUEST, Json(ErrorResponse { error: msg }))
    };
    let err500 = |msg: String| -> (StatusCode, Json<ErrorResponse>) {
        (StatusCode::INTERNAL_SERVER_ERROR, Json(ErrorResponse { error: msg }))
    };

    // 1. Decrypt or extract sensitive payload
    let sensitive: SensitivePayload = if let Some(ref encrypted) = req.encrypted_payload {
        // ECIES mode: decrypt the payload
        let ciphertext = decode_hex(encrypted).map_err(|e| err(e))?;
        let sk = ecies::SecretKey::parse_slice(&state.ecies_secret_key)
            .map_err(|e| err(format!("ECIES key error: {}", e)))?;
        let plaintext = ecies::decrypt(&sk.serialize(), &ciphertext)
            .map_err(|_| err("Encrypted payload could not be decrypted".into()))?;
        serde_json::from_slice(&plaintext)
            .map_err(|e| err(format!("Invalid decrypted JSON: {}", e)))?
    } else {
        // Plaintext mode (backward compatible)
        SensitivePayload {
            consent_signature: req.consent_signature.clone().ok_or_else(|| err("consent_signature required".into()))?,
            cert_der: req.cert_der.clone().ok_or_else(|| err("cert_der required".into()))?,
            cert_chain: req.cert_chain.clone().ok_or_else(|| err("cert_chain required".into()))?,
            ownership_sig: req.ownership_sig.clone().ok_or_else(|| err("ownership_sig required".into()))?,
            nullifier_sig: req.nullifier_sig.clone().ok_or_else(|| err("nullifier_sig required".into()))?,
        }
    };

    // 2. Decode inputs
    let cert_der = decode_base64(&sensitive.cert_der).map_err(|e| err(e))?;
    let consent_sig = decode_hex(&sensitive.consent_signature).map_err(|e| err(e))?;
    let ownership_sig = decode_hex(&sensitive.ownership_sig).map_err(|e| err(e))?;
    let nullifier_sig = decode_hex(&sensitive.nullifier_sig).map_err(|e| err(e))?;
    let registrant = decode_address(&req.registrant).map_err(|e| err(e))?;
    let registry_address = decode_address(&req.registry_address).map_err(|e| err(e))?;
    let ca_merkle_root = decode_hash(&req.ca_merkle_root).map_err(|e| err(e))?;
    let ca_merkle_proof: Vec<[u8; 32]> = req.ca_merkle_proof.iter()
        .map(|s| decode_hash(s))
        .collect::<Result<Vec<_>, _>>()
        .map_err(|e| err(e))?;

    let cert_chain: Vec<Vec<u8>> = sensitive.cert_chain.iter()
        .map(|s| decode_base64(s))
        .collect::<Result<Vec<_>, _>>()
        .map_err(|e| err(e))?;

    let crl_der = match &req.crl_data {
        Some(s) if !s.is_empty() => decode_base64(s).map_err(|e| err(e))?,
        _ => Vec::new(),
    };

    // 2. Verify consent FIRST — before any proving work
    let prover_url = std::env::var("PROVER_URL")
        .unwrap_or_else(|_| "http://localhost:9090".to_string());

    let expected_consent = build_consent_message(
        &prover_url,
        &req.registry_address,
        req.chain_id,
        &req.registrant,
        req.timestamp,
    );

    verify_consent(&cert_der, &consent_sig, &expected_consent)
        .map_err(|e| (StatusCode::FORBIDDEN, Json(ErrorResponse { error: e })))?;

    // Check consent timestamp freshness (10 minutes)
    let now = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs();
    if now.abs_diff(req.timestamp) > 600 {
        return Err(err("Consent expired (>10 min)".to_string()));
    }

    // 3. Parse the certificate subject (consent verified, identity observable).
    //    The compliance record is written after proving (see below) so it can
    //    include the on-chain nullifier.
    let cert_subject = parse_cert_subject(&cert_der);

    tracing::info!(
        "Proving for registrant={} cn={} serial={}",
        req.registrant, cert_subject.common_name, cert_subject.serial
    );

    // 4. Build SP1 stdin and generate proof
    let stdin = zk_x509_script::build_stdin(&zk_x509_script::StdinParams {
        cert_der: &cert_der,
        ownership_sig: &ownership_sig,
        nullifier_sig: &nullifier_sig,
        cert_chain: &cert_chain,
        timestamp: req.timestamp,
        crl_der: &crl_der,
        registrant: &registrant,
        wallet_index: req.wallet_index,
        max_wallets: req.max_wallets,
        disclosure_mask: req.disclosure_mask,
        required_country: parse_optional_bytes32(&req.required_country),
        required_org: parse_optional_bytes32(&req.required_org),
        required_org_unit: parse_optional_bytes32(&req.required_org_unit),
        required_common_name: parse_optional_bytes32(&req.required_common_name),
        ca_merkle_proof: &ca_merkle_proof,
        ca_merkle_root,
        registry_address: &registry_address,
        chain_id: req.chain_id,
    });

    // Run proving in a blocking task to avoid tokio runtime nesting
    // (SP1 ProverClient internally uses block_on which conflicts with async)
    // TODO: pre-initialize client + pk at startup for better performance.
    // Currently, setup() runs per-request. SP1 ProvingKey is a trait object
    // that doesn't implement Send/Sync, preventing Arc sharing. Revisit when
    // the SP1 SDK exposes a thread-safe ProvingKey.
    let start = Instant::now();
    let prove_result = tokio::task::spawn_blocking(move || {
        let client = ProverClient::from_env();
        let pk = client.setup(ZK_X509_ELF)?;
        let proof: SP1ProofWithPublicValues = client
            .prove(&pk, stdin)
            .groth16()
            .run()?;
        Ok::<_, Box<dyn std::error::Error + Send + Sync>>(proof)
    })
    .await
    .map_err(|e| err500(format!("Task join error: {}", e)))?
    .map_err(|e| err500(format!("Proving failed: {}", e)))?;

    let proving_time_ms = start.elapsed().as_millis() as u64;

    // 5. Encode proof for on-chain submission
    let public_values = prove_result.public_values.as_slice().to_vec();
    let proof_bytes = prove_result.bytes();

    tracing::info!("Proof generated: proving_time={}ms", proving_time_ms);

    // 6. Log compliance now that the proof (and thus the nullifier) exists.
    //    Decode the public values via the canonical `PublicValuesStruct` so the
    //    nullifier — the join key against the on-chain IdentityRegistry
    //    registration — survives any future reordering of the struct.
    let nullifier = match PublicValuesStruct::abi_decode(public_values.as_slice()) {
        Ok(pv) => format!("0x{}", hex::encode(pv.nullifier)),
        Err(_) => String::new(),
    };
    let logged_at = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_secs();
    log_compliance(&ComplianceRecord {
        timestamp: logged_at,
        registrant: req.registrant.clone(),
        common_name: cert_subject.common_name,
        org: cert_subject.org,
        org_unit: cert_subject.org_unit,
        country: cert_subject.country,
        serial: cert_subject.serial,
        not_after: cert_subject.not_after,
        nullifier,
        consent_verified: true,
        consent_message: expected_consent,
        consent_signature: sensitive.consent_signature.clone(),
    });

    Ok(Json(ProveResponse {
        proof: format!("0x{}", hex::encode(&proof_bytes)),
        public_values: format!("0x{}", hex::encode(&public_values)),
        proving_time_ms,
    }))
}

// ── Main ────────────────────────────────────────────────────────

fn main() {
    sp1_sdk::utils::setup_logger();
    dotenv::dotenv().ok();

    let port = std::env::var("PROVER_PORT").unwrap_or_else(|_| "9090".to_string());
    let prover_url = std::env::var("PROVER_URL")
        .unwrap_or_else(|_| format!("http://localhost:{}", port));

    let app_state = Arc::new(AppState::new());
    println!("ECIES public key: 0x{}", hex::encode(&app_state.ecies_public_key));

    tokio::runtime::Builder::new_multi_thread()
        .enable_all()
        .build()
        .unwrap()
        .block_on(async move {
            let cors = CorsLayer::new()
                .allow_origin(AllowOrigin::any())
                .allow_methods(tower_http::cors::Any)
                .allow_headers(tower_http::cors::Any);

            let app = Router::new()
                .route("/api/prove", post(prove_handler))
                .route("/api/pubkey", get(pubkey_handler))
                .route("/api/health", get(health_handler))
                .route("/api/compliance", get(compliance_handler))
                .with_state(app_state)
                .layer(cors)
                .layer(axum::extract::DefaultBodyLimit::max(10 * 1024 * 1024)); // 10MB

            let addr = format!("0.0.0.0:{}", port);
            tracing::info!("Delegated prover server at {}", prover_url);
            println!("Delegated prover server running at {}", prover_url);
            println!("   POST /api/prove      - Generate ZK proof (supports ECIES encryption)");
            println!("   GET  /api/pubkey     - ECIES public key for encrypting requests");
            println!("   GET  /api/health     - Server status");
            println!("   GET  /api/compliance - Query compliance records by wallet (KYC reconciliation)");

            let listener = tokio::net::TcpListener::bind(&addr).await.unwrap();
            axum::serve(listener, app).await.unwrap();
        });
}
